class Solution:
    def digitCount(self, num: str) -> bool:
        freq = [0] * 10
        for c in num:
            d = int(c)
            freq[d] += 1
        for i in range(len(num)):
            expected = int(num[i])
            if freq[i] != expected:
                return False
        return True

